                for adj in link_map[index]:
                    if paired[adj] == 0 and paired[index] == 0:
                        paired[adj] = index
                        paired[index] = adj

        result = 1
        for node in range(1, total_nodes + 1):
            if result == 1 and paired[node] == 0:
                path_queue = []
                for nxt in link_map[node]:
                    path_queue.append([node, nxt, -1, [node, nxt]])
                step = 0
                solved = False
                while step < len(path_queue) and not solved:
                    trace = paired[path_queue[step][1]]
                    if trace not in path_queue[step][3]:
                        for branch in link_map[trace]:
                            if not solved and branch not in path_queue[step][3]:
