                                    path_queue.append([trace, branch, step])
                                    backstep = len(path_queue) - 1
                                    while backstep > -1:
                                        left = path_queue[backstep][0]
                                        right = path_queue[backstep][1]
                                        paired[left] = right
                                        paired[right] = left
                                        backstep = path_queue[backstep][2]
                                else:
                                    updated_path = list(path_queue[step][3])
                                    updated_path.extend([trace, branch])
                                    path_queue.append([trace, branch, step, updated_path])
                    step += 1
                if not solved:
                    result = 0
    print('YES' if result else 'NO')

