#include<stdio.h>
int graph[102][102],mark[102],degree[102],n,m;
int find1()
{
    int i,j,sel=-1,deg=1000;
    for(j=1;j<=n;j++)
    {
        if(mark[j]==0&&degree[j]<deg)
        {
            deg=degree[j];
            sel=j;
        }
    }
    return sel;
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int i,j,k,x,y,flag;
        scanf("%d%d",&n,&m);
        for(j=1;j<=n;j++)
        {
            mark[j]=0;
            degree[j]=0;
            for(i=1;i<=n;i++)
                graph[j][i]=0;
        }
        for(i=0;i<m;i++)
        {
            scanf("%d%d",&x,&y);
            if(graph[x][y]==0)
            {
                degree[x]++;
                degree[y]++;
                graph[x][y]=graph[y][x]=1;
            }
        }
        if(n%2!=0||m<n/2)
        {
            printf("NO\n");
            continue;
        }
        flag=0;
        for(i=1;i<=n;i++)
        {
            int sel=find1();
            if(sel==-1)
                break;
            int adj=0,deg=1001;
            for(k=1;k<=n;k++)
            {
                if(graph[sel][k]==1&&degree[k]<deg&&mark[k]==0)
                {
                    adj=k;
                    deg=degree[k];
                }
            }
            if(adj==0)
            {
                flag=1;
                break;
            }
            mark[sel]=mark[adj]=1;
            for(k=1;k<=n;k++)
            {
                if(graph[sel][k]==1)
                {
                    degree[k]--;
                    degree[sel]--;
                    graph[sel][k]=graph[k][sel]=0;
                }
                if(graph[adj][k]==1)
                {
                    degree[k]--;
                    degree[adj]--;
                    graph[adj][k]=graph[k][adj]=0;
                }
            }
        }
        if(flag==0)
            printf("YES\n");
        else
            printf("NO\n");
    }
    return 0;
}

