import java.util.*;

public class Main {
    static int N, M;
    static ArrayList < Integer > [] adj;
    static boolean[] visited;
    static boolean foundMatching;

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();

        while (T--> 0) {
            N = sc.nextInt();
            M = sc.nextInt();

            adj = new ArrayList[N + 1];
            for (int i = 1; i <= N; i++) {
                adj[i] = new ArrayList < > ();
            }

            for (int i = 0; i < M; i++) {
                int u = sc.nextInt();
                int v = sc.nextInt();
                if (u != v) { // skip self-loops
                    adj[u].add(v);
                    adj[v].add(u);
                }
            }

            if (N % 2 != 0) {
                System.out.println("NO");
                continue;
            }

            visited = new boolean[N + 1];
            foundMatching = false;

            backtrack(1, 0);

            System.out.println(foundMatching ? "YES" : "NO");
        }

        sc.close();
    }

    static void backtrack(int node, int matchedCount) {
        if (matchedCount == N / 2) {
            foundMatching = true;
            return;
        }

        while (node <= N && visited[node]) node++; // skip visited

        if (node > N) return;

        for (int neighbor: adj[node]) {
            if (!visited[neighbor]) {
                visited[node] = visited[neighbor] = true;
                backtrack(node + 1, matchedCount + 1);
                if (foundMatching) return;
                visited[node] = visited[neighbor] = false;
            }
        }
    }
}
